#include <string>
#include <vector>

bool isPrefixString(std::string s, std::vector<std::string>& words) {
    std::string prefix = "";
    for (std::string word : words) {
        prefix += word;
        if (prefix == s) {
            return true;
        }
    }
    return false;
}
```
